insert into knowledge_nodes (id, project_id, node_key, label, category, sub_label, facts, talkpoint, description, sort_order) values
  ('2d54a817-1bc1-5d87-afc8-2f925b18da2e','00000000-0000-0000-0000-00000000b007','bcons','Bcons Ngôi Sao Hoàng Nam','project','Căn hộ vừa túi tiền · Thống Nhất, Đông Hòa','[{"key":"Tên thương mại","value":"Bcons Ngôi Sao Hoàng Nam (≈ \"Bcons Hoàng Nam Ngôi Sao\")"},{"key":"Vị trí","value":"Đường Thống Nhất, P. Đông Hòa, TP.HCM (Dĩ An cũ, Bình Dương)"},{"key":"Quy mô toàn khu","value":"7.877,8 m² (theo CĐT)"},{"key":"Diện tích xây dựng","value":"4.019 m² · mật độ ~51,66%"},{"key":"Quy mô tháp","value":"1 tòa cao 21 tầng + 1 tầng hầm"},{"key":"Số căn hộ","value":"372 căn (diện tích 50–67 m²/căn)"},{"key":"Dân số dự kiến","value":"~1.274 cư dân"},{"key":"Phát triển","value":"Bcons Group × CTCP Đầu tư Dự án Hoàng Nam"},{"key":"Tài trợ","value":"Ngân hàng OCB (Phương Đông)"},{"key":"Động thổ","value":"24/01/2026"},{"key":"Bàn giao","value":"Dự kiến Quý III/2028"}]'::jsonb,null,'Định danh dự án Câu chuyện đầu tư trong 3 dòng: căn hộ vừa túi tiền do CĐT có track record "không bàn giao trễ", trên trục Thống Nhất sầm uất cạnh Làng Đại học & Metro số 1 — đón cú hích sáp nhập Bình Dương vào TP.HCM. Quy mô nhỏ (1 tháp 372 căn), dòng thuê thực mạnh, nhưng vừa động thổ nên pháp lý/giá cần xác minh kỹ.',0),
  ('6326b747-7f40-5a63-a2ff-6e281943751b','00000000-0000-0000-0000-00000000b007','tq-vitri','Vị trí Thống Nhất – Đông Hòa','project','Cửa ngõ Đông TP.HCM · cạnh Làng ĐH','[]'::jsonb,null,'Tọa độ & kết nối Dự án nằm trên/đường nhánh kết nối đường Thống Nhất (trục 32m, 6 làn nối Thủ Đức – Dĩ An ra Metro số 1), phường Đông Hòa. Tọa độ ~10,7765, 106,7019. • Cách trục Thống Nhất ~200m; kề khu đô thị 15ha và chuỗi dự án Bcons (Plaza, City, Center City) • Liền kề Đại học Quốc gia TP.HCM / Làng Đại học • Kết nối Metro số 1, Bến xe Miền Đông mới, QL1K, QL1A (Đỗ Mười), Phạm Văn Đồng, Vành đai 3 • ~30–40 phút về trung tâm Quận 1; gần các KCN Sóng Thần, Linh Trung, VSIP',1),
  ('22cef3ef-9465-5c64-8ff3-686ecfa865ce','00000000-0000-0000-0000-00000000b007','tq-quymo','Quy mô dự án','project','7.877,8 m² · 1 tháp 21 tầng · 372 căn','[{"key":"Quy mô toàn khu","value":"7.877,8 m²"},{"key":"Diện tích xây dựng","value":"4.019 m²"},{"key":"Mật độ xây dựng","value":"~51,66%"},{"key":"Số tháp","value":"1 tòa · 21 tầng nổi + 1 hầm"},{"key":"Số căn","value":"372 căn (50–67 m²)"},{"key":"Dân số","value":"~1.274 cư dân"}]'::jsonb,null,'Đây là dự án quy mô nhỏ, 1 tháp — khác hẳn các đại đô thị. Ưu điểm: cộng đồng gọn, dễ quản lý vận hành. Nhược điểm: ít dư địa tiện ích lớn; mật độ xây dựng cao (~51,66%) nên không gian xanh hạn chế.',2),
  ('facbbe1d-50d3-54ac-824c-8216d3381fcf','00000000-0000-0000-0000-00000000b007','tq-mauthuan','Cảnh báo mâu thuẫn số liệu','project','Phân biệt Hoàng Nam vs Bcons City','[]'::jsonb,null,'Trên thị trường tồn tại nhiều con số quy mô khác nhau cho cái tên "Bcons Ngôi Sao". Nguyên nhân: dễ nhầm 2 dự án khác nhau. Một số trang còn ghi "3.680 m²" hoặc "29 tầng + 2 hầm" cho Hoàng Nam — không khớp số liệu chính thức (7.877,8 m², 21 tầng, 1 hầm).',3),
  ('156e18cd-b493-5457-94d8-9451a7e87396','00000000-0000-0000-0000-00000000b007','tq-thietke','Thiết kế & định hướng xanh','project','Kiến trúc hiện đại · đón nắng gió tự nhiên','[]'::jsonb,null,'Theo công bố tại lễ động thổ: tháp căn hộ được thiết kế đón nắng và gió tự nhiên, hướng "sống xanh – bền vững", vật liệu thân thiện môi trường. Mặt đứng hiện đại, tối ưu công năng.',4),
  ('d0835ac9-5c28-5b06-99f4-b743f63cb9a4','00000000-0000-0000-0000-00000000b007','tq-dinhvi','Định vị phân khúc','project','Vừa túi tiền · TOD · KHÔNG "siêu sang"','[]'::jsonb,null,'Định vị đúng của dự án: tổng giá trị căn vừa tầm + thương hiệu quen thuộc + vị trí có dòng thuê thực, hướng gia đình trẻ, chuyên gia, trí thức, người lao động khu Đông. Mô hình TOD (Transit-Oriented Development) — phát triển bám hạ tầng giao thông công cộng (Metro số 1) — là khung định vị Bcons theo đuổi.',5),
  ('fef5749b-825e-589d-8213-594e75a54bbf','00000000-0000-0000-0000-00000000b007','tq-sapnhap','Hiệu ứng sáp nhập TP.HCM','project','Từ 1/7/2025: địa chỉ "TP.HCM"','[{"key":"Phường Đông Hòa mới","value":"Gộp Đông Hòa + Bình An + Bình Thắng · ~21,89 km² · ~132.000–183.000 dân"},{"key":"Định hướng","value":"Đô thị tri thức & dịch vụ, tận dụng ĐHQG TP.HCM"},{"key":"Trụ sở phường","value":"Đặt tại Bình An (cũ)"}]'::jsonb,null,'Từ 1/7/2025 (Nghị quyết 1685/NQ-UBTVQH15 & NQ 202/2025/QH15), Bình Dương + Bà Rịa–Vũng Tàu + TP.HCM cũ hợp nhất thành TP.HCM mới. TP Dĩ An tách thành 3 phường: Đông Hòa, Dĩ An, Tân Đông Hiệp.',6),
  ('e5e4e935-6d5b-5d5a-a065-90e5934fd6ee','00000000-0000-0000-0000-00000000b007','cdt-bcons','Bcons Group','developer','Thành lập 2013 · Lê Như Thạch · 14 dự án','[{"key":"Tuổi đời (2025)","value":"12 năm"},{"key":"Quy mô","value":"Hơn 15 công ty thành viên · 14 dự án căn hộ (Dĩ An cũ)"},{"key":"Lõi năng lực","value":"Tư vấn thiết kế + tổng thầu xây dựng + đầu tư BĐS (mạnh khâu thi công)"},{"key":"Mở rộng","value":"Giáo dục (Bcons Uni Valley), BIM, hạ tầng đô thị"},{"key":"MST","value":"0314635755"}]'::jsonb,null,'Bcons Group (Tập đoàn Bcons) thành lập 06/3/2013, tiền thân là Công ty TNHH Tư vấn Thiết kế và Quản lý dự án Hồng Ngọc (khởi đầu 8 nhân sự). Chủ tịch sáng lập ông Lê Như Thạch (tốt nghiệp & từng giảng dạy ĐH Bách Khoa TP.HCM). Bcons là nhà phát triển tầm trung, ra hàng đều, chuyên phân khúc vừa túi tiền cho người thu nhập trung bình – khá tại đô thị vệ tinh (Dĩ An, Thuận An, Biên Hòa, Bình Chánh).',7),
  ('aafccbf8-d800-5196-bd22-806318bfad53','00000000-0000-0000-0000-00000000b007','cdt-trackrecord','Track record bàn giao','developer','"Chưa dự án nào bàn giao trễ" · 8 dự án ra sổ','[]'::jsonb,null,'Điểm mạnh lớn nhất của Bcons khi tư vấn — uy tín giao nhà & ra sổ: • Ông Lê Như Thạch: "Chúng tôi chưa có dự án nào bàn giao nhà trễ cho khách hàng." • Tổng kết (theo trang Bcons): 14 dự án triển khai · 10 dự án bàn giao đúng tiến độ · 8 dự án đã bàn giao sổ hồng. • Cam kết hoàn thiện sổ riêng sau ~6 tháng giao nhà (điển hình Bcons Suối Tiên, Miền Đông). • Dự án đã bàn giao + sổ: Bcons Plaza, Bcons Bee (2021), Bcons Polygon (9/2024), Bcons Suối Tiên, Bcons Miền Đông, Bcons Garden, Bcons Green View…',8),
  ('17b6c1e5-487d-5937-b0d3-e1b55fa71ff9','00000000-0000-0000-0000-00000000b007','cdt-danhmuc','Hệ sinh thái dự án Bcons','developer','Plaza · City · Center City · Polaris…','[]'::jsonb,null,'Chuỗi ~14+ dự án căn hộ, phần lớn tại Dĩ An (Đông Hòa, An Bình, Bình An): Kế hoạch: đưa ra thị trường ~10.000–12.000 căn/năm, mở rộng khu Tây TP.HCM, Đà Lạt, Bàu Bàng, Đồng Nai.',9),
  ('389117ec-e45f-5928-8a2d-33677ec6dfa4','00000000-0000-0000-0000-00000000b007','cdt-hoangnam','CTCP Đầu tư Dự án Hoàng Nam','developer','Đối tác · ông Hoàng Văn Tâm','[]'::jsonb,null,'Công ty Cổ phần Đầu tư Dự án Hoàng Nam là đối tác đồng phát triển; ông Hoàng Văn Tâm – Chủ tịch HĐQT kiêm Tổng Giám đốc – tham dự lễ động thổ 24/1/2026.',10),
  ('b5d84324-0969-57ad-9782-773ba3db4f9a','00000000-0000-0000-0000-00000000b007','cdt-tod','Chiến lược TOD & vừa túi tiền','developer','Bám Metro · 10.000 căn/năm','[]'::jsonb,null,'Ông Lê Như Thạch nhấn mạnh mô hình TOD (Transit-Oriented Development) — phát triển đô thị bám tuyến giao thông công cộng — là "xu thế tất yếu" tại Đông Nam Bộ. Bcons định vị căn hộ vừa túi tiền, mục tiêu tỷ lệ lấp đầy >90% các dự án đã hoàn thành.',11),
  ('c1144001-09bc-5429-a806-27486b8e5c47','00000000-0000-0000-0000-00000000b007','pl-hientrang','Hiện trạng pháp lý','legal','Mới động thổ · cần xác minh hồ sơ','[]'::jsonb,null,'Dự án mới động thổ 24/01/2026, đang ở giai đoạn khởi đầu. CĐT tuyên bố "sự chuẩn bị kỹ lưỡng về pháp lý" tại lễ động thổ, nhưng chưa công bố công khai số quyết định 1/500, giấy phép xây dựng, hay văn bản đủ điều kiện bán nhà ở hình thành trong tương lai cho riêng dự án này.',12),
  ('f4d4263c-e00a-5282-95ad-a91be11f262f','00000000-0000-0000-0000-00000000b007','pl-benchmark','Bảo chứng pháp lý từ Bcons','legal','Bcons City có VB đủ ĐK bán · 8 dự án ra sổ','[]'::jsonb,null,'Tuy dự án Hoàng Nam còn mới, "lịch sử pháp lý" của Bcons là tham chiếu tích cực: • Bcons City (cùng đường Thống Nhất) đã có văn bản đủ điều kiện bán số 71/SXD-QLN ngày 06/03/2025 — minh chứng Bcons hoàn tất được thủ tục bán hàng. • 8 dự án Bcons đã bàn giao sổ hồng cho cư dân; cam kết sổ riêng sau ~6 tháng giao nhà. • Nhiều dự án (Garden, Miền Đông, Green View, Polygon) pháp lý rõ ràng, đã ra sổ.',13),
  ('093f38c5-b3fa-5d18-9dab-928e13d17d31','00000000-0000-0000-0000-00000000b007','pl-sohuu','Hình thức sở hữu','legal','Căn hộ ở · sở hữu lâu dài (dự kiến)','[]'::jsonb,null,'Là "khu nhà ở cao tầng" (căn hộ chung cư để ở), thông lệ tại các dự án Bcons là sổ hồng sở hữu lâu dài cho người mua trong nước. Chi tiết (thời hạn, phần sở hữu chung/riêng, room cho người nước ngoài) cần xác nhận trong HĐMB & GCN của dự án.',14),
  ('c26bedd2-16d5-5977-865b-2dc2e04e7def','00000000-0000-0000-0000-00000000b007','pl-ocb','Ngân hàng OCB','legal','Đồng hành tài trợ/bảo lãnh','[]'::jsonb,null,'Tại lễ động thổ có sự hiện diện của Ngân hàng TMCP Phương Đông (OCB) — ông Phạm Thanh Hoàn, Giám đốc CIB, Trung tâm Kinh doanh Hội sở. OCB nhiều khả năng là ngân hàng tài trợ vốn dự án và/hoặc cho vay người mua, bảo lãnh.',15),
  ('86443b53-91a6-54b8-b4e6-be5d560035a7','00000000-0000-0000-0000-00000000b007','pl-checklist','Checklist trước cọc','legal','6 bước — chú ý dự án mới động thổ','[]'::jsonb,null,'• 1. Quyết định chủ trương đầu tư + quy hoạch 1/500 đã duyệt. • 2. Giấy phép xây dựng của dự án (rất quan trọng vì mới động thổ). • 3. Văn bản đủ điều kiện bán nhà ở hình thành trong tương lai của Sở Xây dựng — nếu CHƯA có, chỉ nên "giữ chỗ" có hoàn lại, không thanh toán lớn. • 4. Làm rõ pháp nhân ký HĐMB (Bcons hay Hoàng Nam) và trách nhiệm bàn giao/ra sổ. • 5. Chứng thư bảo lãnh ngân hàng (OCB) ghi đúng mã căn. • 6. Tiến độ thanh toán theo trần luật: ≤70% trước bàn giao, ≤95% trước khi cấp sổ.',16),
  ('751341bf-7adb-50a2-99ab-264ae3950f1d','00000000-0000-0000-0000-00000000b007','pk-cancho','372 căn hộ','masterplan','50–67 m² · 1 tháp 21 tầng','[{"key":"Tổng căn","value":"372 căn hộ"},{"key":"Diện tích","value":"50–67 m²/căn (dự kiến)"},{"key":"Tháp","value":"1 tòa · 21 tầng nổi + 1 hầm"},{"key":"Dân số","value":"~1.274 cư dân"}]'::jsonb,null,'Diện tích 50–67 m² phù hợp căn 1–2 phòng ngủ — đúng "khẩu vị" sản phẩm vừa túi tiền cho gia đình trẻ & cho thuê. Quy mô 372 căn nhỏ → cộng đồng gọn, mật độ cư dân/tiện ích cần theo dõi.',17),
  ('60084725-c1d4-514a-9700-7e8d19c730cf','00000000-0000-0000-0000-00000000b007','pk-loaihinh','Loại căn (dự kiến)','masterplan','1–2PN diện tích nhỏ','[]'::jsonb,null,'CĐT chưa công bố bảng layout chi tiết. Dựa trên dải diện tích 50–67 m² và dòng sản phẩm Bcons (so sánh Bcons City: 36–58 m²; Polygon: 45–67 m²), cơ cấu dự kiến nghiêng về 1PN (~50 m²) và 2PN (~58–67 m²).',18),
  ('fb439a74-b9e7-562f-a3ab-1e0da6d1dd50','00000000-0000-0000-0000-00000000b007','pk-bangiao','Tiêu chuẩn bàn giao','masterplan','Nội thất cơ bản (chuẩn Bcons)','[]'::jsonb,null,'Chưa có công bố riêng cho Hoàng Nam. Chuẩn bàn giao điển hình của Bcons (tham chiếu Bcons Center City): sàn phòng khách gạch 60×60, sàn phòng ngủ gỗ, trần thạch cao + đèn, tủ bếp trên–dưới, thiết bị vệ sinh cơ bản.',19),
  ('523b3107-def9-53ed-a35d-51a8bed6ecf7','00000000-0000-0000-0000-00000000b007','pk-tiendo','Tiến độ & bàn giao','masterplan','Động thổ 1/2026 → bàn giao Q3/2028','[]'::jsonb,null,'Chu kỳ xây dựng ~2,5 năm từ động thổ đến bàn giao — phù hợp 1 tháp 21 tầng. Nhà đầu tư cần tính thời gian chôn vốn tới 2028 trước khi có dòng tiền cho thuê.',20),
  ('ce5422ae-289a-5207-9030-8c7cb2f5fe59','00000000-0000-0000-0000-00000000b007','pk-matdo','Mật độ & không gian','masterplan','MĐXD ~51,66% · lưu ý cây xanh','[]'::jsonb,null,'Diện tích xây dựng 4.019 m² trên 7.877,8 m² → mật độ xây dựng ~51,66%.',21),
  ('f2ce44ed-cac9-5b85-b41e-5e4b55997075','00000000-0000-0000-0000-00000000b007','ti-hoboi','Hồ bơi','amenity','Thư giãn nội khu','[]'::jsonb,null,'Dự án có hồ bơi trong hệ tiện ích "all-in-one". Với dự án 1 tháp mật độ cao, hồ bơi thường bố trí ở tầng đế/tầng kỹ thuật hoặc sân thượng — quy mô vừa phải phục vụ ~1.274 cư dân.',22),
  ('ad30aeaa-fa08-5309-8621-7c91f0205064','00000000-0000-0000-0000-00000000b007','ti-congvien','Công viên & đường dạo','amenity','Mảng xanh nội khu','[]'::jsonb,null,'Công viên cây xanh và đường dạo bộ — "lá phổi xanh" nội khu. Quy mô bị giới hạn bởi diện tích đất nhỏ (7.877,8 m²) và mật độ xây dựng cao; nên xem đây là không gian sinh hoạt vừa đủ chứ không phải công viên lớn.',23),
  ('f48712ed-89b0-54ef-902e-26b4b70af043','00000000-0000-0000-0000-00000000b007','ti-treem','Khu trẻ em & nhà trẻ','amenity','Hướng gia đình trẻ','[]'::jsonb,null,'Khu vui chơi trẻ em và nhà trẻ nội khu — phù hợp tệp khách gia đình trẻ. Tiện ích hướng gia đình giúp giữ chân cư dân ở thật và hỗ trợ nhu cầu thuê của hộ có con nhỏ.',24),
  ('e1616985-2ca6-56cc-a0b8-7436286aa0b8','00000000-0000-0000-0000-00000000b007','ti-theduc','Gym, Yoga & BBQ','amenity','Tiện ích thể chất – sinh hoạt','[]'::jsonb,null,'Hệ tiện ích thể chất – sinh hoạt: phòng Gym & Yoga, khu BBQ. Đáp ứng nhu cầu vận động và gắn kết cộng đồng của cư dân trẻ — nhóm khách thuê tiềm năng quanh Làng Đại học/KCN.',25),
  ('98045d75-b365-5a83-9523-513a7e180259','00000000-0000-0000-0000-00000000b007','ti-thuongmai','Siêu thị mini & khối đế','amenity','Tiện ích "all-in-one"','[]'::jsonb,null,'Siêu thị mini và các tiện ích thương mại khối đế tạo mô hình "all-in-one" — cư dân không cần đi xa cho nhu cầu cơ bản. Khối thương mại cũng là nguồn dòng tiền/giá trị cho căn shophouse (nếu có) và tiện ích cho khách thuê.',26),
  ('077fa503-df92-55c8-aee2-64a6924404a4','00000000-0000-0000-0000-00000000b007','ht-metro','Metro số 1','infra','Đã vận hành 12/2024 · ga cuối Suối Tiên','[]'::jsonb,null,'Metro số 1 (Bến Thành – Suối Tiên) đã vận hành thương mại từ 12/2024. Ga cuối tại khu vực Suối Tiên / Bến xe Miền Đông mới — gần trục Thống Nhất qua Làng Đại học.',27),
  ('073c1a8d-35d2-5487-9f5e-efbdff68184f','00000000-0000-0000-0000-00000000b007','ht-bxmd','Bến xe Miền Đông mới','infra','Đầu mối vận tải liên vùng','[]'::jsonb,null,'Bến xe Miền Đông mới (một trong những bến xe lớn nhất nước) nằm trên địa bàn cửa ngõ Đông, kết nối Metro số 1 và các tuyến liên tỉnh. Cùng ga metro cuối, đây là đầu mối giao thông công cộng tạo lưu lượng & nhu cầu lưu trú/thuê quanh khu vực Thống Nhất – Đông Hòa.',28),
  ('73e27167-2b05-50d3-9a03-363912d4c1a5','00000000-0000-0000-0000-00000000b007','ht-dhqg','ĐHQG TP.HCM / Làng Đại học','infra','Nguồn cầu thuê khổng lồ','[]'::jsonb,null,'Đại học Quốc gia TP.HCM (Làng Đại học) nằm ngay địa bàn phường Đông Hòa — hàng trăm nghìn sinh viên, giảng viên, cán bộ. Đây là nguồn cầu thuê căn hộ ổn định và bền vững nhất của khu vực.',29),
  ('3fca6ff7-d023-5a12-ac32-02db6ff98ae3','00000000-0000-0000-0000-00000000b007','ht-thongnhat','Đường Thống Nhất','infra','32m, 6 làn · GĐ2 2026–2028','[]'::jsonb,null,'Đường Thống Nhất: giai đoạn 1 mở rộng 32m, 6 làn (2022–2025, cơ bản hoàn thành), đi qua Đông Hòa & Bình An; là một phần tuyến Vành đai 2 ĐHQG. Giai đoạn 2 (QL1K → Trần Hưng Đạo, ~897m) thực hiện 2026–2028; trục Trần Hưng Đạo – Thống Nhất (Đông–Tây) kết nối Ga Dĩ An + Ga Metro số 1 + Bến xe Miền Đông mới.',30),
  ('73d44842-8cd6-5982-a1a2-555792b071f3','00000000-0000-0000-0000-00000000b007','ht-vanhdai','Vành đai 3 & trục liên vùng','infra','Mỹ Phước–Tân Vạn · Xa lộ HN · QL1K','[]'::jsonb,null,'Phường Đông Hòa là cửa ngõ phía Đông TP.HCM, hội tụ nhiều trục lớn: Vành đai 3 TP.HCM, Mỹ Phước – Tân Vạn, Xa lộ Hà Nội, đường Đỗ Mười (QL1A), QL1K, Phạm Văn Đồng.',31),
  ('41eb69ab-756f-5665-a1f2-de9830e481cd','00000000-0000-0000-0000-00000000b007','ht-kcn','Khu công nghiệp lân cận','infra','Sóng Thần · VSIP · Linh Trung · CNC','[]'::jsonb,null,'Bao quanh khu vực là các KCN lớn: Sóng Thần 1&2, VSIP, Linh Trung, Khu Công nghệ cao — cách 5–10 phút. Đây là nguồn cầu thuê thứ hai (sau Làng ĐH): chuyên gia, kỹ sư, công nhân tay nghề cao.',32),
  ('7c5cc2d6-c3b0-5f7a-970b-7dca5520f885','00000000-0000-0000-0000-00000000b007','ht-tacdong','Tác động hạ tầng tổng hợp','infra','TOD + cửa ngõ Đông + sáp nhập','[]'::jsonb,null,'Cộng hưởng các lớp hạ tầng quanh dự án: • Metro số 1 đã chạy + đề xuất kéo dài → trục TOD • Bến xe Miền Đông mới → đầu mối liên vùng • ĐHQG + KCN → cầu thuê kép, bền vững • Đường Thống Nhất nâng cấp + Vành đai 3 → kết nối tốt hơn • Sáp nhập TP.HCM (1/7/2025) → nâng định vị & kỳ vọng đồng bộ hạ tầng',33),
  ('30e1f9d2-7f92-5289-82ce-fe1e2f1962c9','00000000-0000-0000-0000-00000000b007','cs-gia','Giá bán','policy','Chưa công bố chính thức · benchmark hệ Bcons','[]'::jsonb,null,'Dự án vừa động thổ — chưa có bảng giá chính thức công bố. CĐT nhấn mạnh "giai đoạn 1 luôn có mức giá tốt nhất". Tham chiếu mặt bằng giá hệ Bcons cùng khu để ước lượng: Ước lượng Hoàng Nam: nhiều khả năng rơi vào dải ~45–60 triệu/m² (là dự án mới nhất, cùng trục Thống Nhất với Bcons City/Center City), tổng giá căn 1–2PN khoảng ~2,2–3,5 tỷ.',34),
  ('bf7c7a99-a7a0-5ca0-a511-7c5593894a28','00000000-0000-0000-0000-00000000b007','cs-benchmark','So sánh giá khu vực','policy','Dĩ An – Thủ Đức 12/2025','[]'::jsonb,null,'Bối cảnh giá căn hộ Dĩ An – TP. Thủ Đức (khảo sát sàn 12/2025): • Căn hộ vừa túi tiền Dĩ An: ~31–46 triệu/m² (Phú Đông SkyOne ~31,5–38; Bcons Polaris ~39; Bcons City ~46) • Dự án có lợi thế Metro/mới: ~50–60 triệu/m² (Bcons Center City ~55) • Căn hộ cao cấp khu Đông (Thủ Đức lõi): ~60–120 triệu/m²+',35),
  ('55e90cbc-4df4-529d-83a8-f44f015edcbd','00000000-0000-0000-0000-00000000b007','cs-thanhtoan','Chính sách thanh toán','policy','Chuẩn Bcons: trả chậm, NH bảo lãnh','[]'::jsonb,null,'Chưa công bố riêng cho Hoàng Nam. Chính sách điển hình của Bcons (tham chiếu Polaris/City): • Giữ chỗ ~30 triệu, hoàn lại 100% nếu không mua • Thanh toán 10–20% nhận nhà, phần còn lại theo tiến độ • Trả chậm tới ~2 năm không lãi suất, ngân hàng (OCB) bảo lãnh & cho vay • Chiết khấu thanh toán nhanh (vd Polaris CK ~1,1% khi chọn 20% nhận nhà)',36),
  ('c4316284-8350-53ca-87b5-93637d0142df','00000000-0000-0000-0000-00000000b007','cs-yield','Tỷ suất cho thuê','policy','Khu vực ~5–7%/năm · cao hơn lõi','[{"key":"Giá thuê tham khảo","value":"~8–15 triệu/tháng (căn 1–2PN)"},{"key":"Yield khu vực","value":"~5–7%/năm (Phú Đông SkyOne công bố)"},{"key":"So với khu lõi","value":"Lõi TP.HCM chỉ ~2–4%/năm"}]'::jsonb,null,'Khu Dĩ An/Đông Hòa/Làng ĐH có tỷ suất cho thuê cao hơn khu lõi TP.HCM nhờ giá vốn thấp + cầu thuê dày: Nguồn cầu thuê: giảng viên/cán bộ ĐHQG, sinh viên (ở ghép), chuyên gia/kỹ sư KCN. Đây là luận điểm đầu tư mạnh nhất của dự án — dòng tiền cho thuê thực, không phụ thuộc kỳ vọng tăng giá.',37),
  ('3d8f42df-8d5f-5c55-a0a9-209e45fd25bf','00000000-0000-0000-0000-00000000b007','cs-thoidiem','Thời điểm động thổ','policy','Giá GĐ1 tốt nhất — góc nhìn 2 chiều','[]'::jsonb,null,'CĐT lập luận: mua ngay sau động thổ (GĐ1) hưởng giá tốt nhất + chọn căn đẹp + biên tăng giá theo tiến độ cao nhất.',38),
  ('6a484526-4fa1-56a4-a13f-1cc1e01b69fd','00000000-0000-0000-0000-00000000b007','tt-bicanh','Bối cảnh thị trường','comparable','BĐS Dĩ An phục hồi · thanh khoản Bcons tốt','[]'::jsonb,null,'• 6 tháng đầu 2025: BĐS Bình Dương (cũ) phục hồi; giá Thuận An/Dĩ An/Thủ Dầu Một tăng ~10–15% tùy vị trí. • Thanh khoản các dự án Bcons ở Đông Hòa/Tân Đông Hiệp được ghi nhận rất tốt. • Cú hích sáp nhập TP.HCM + Metro vận hành làm tăng quan tâm khu cửa ngõ Đông. Kết luận khung: phân khúc vừa túi tiền gần Metro/ĐHQG đang có cầu thực tốt; Bcons có lợi thế "ra hàng đều + thanh khoản tốt" trong khu vực này.',39),
  ('797fe4bb-91c8-550e-986c-e575dd155403','00000000-0000-0000-0000-00000000b007','tt-bcons-noi','Cạnh tranh nội bộ Bcons','comparable','City · Center City cùng trục Thống Nhất','[]'::jsonb,null,'Ngay trên/cạnh trục Thống Nhất, Hoàng Nam cạnh tranh với chính các dự án Bcons:',40),
  ('99038289-16d7-5ba1-8896-f64700aa4df6','00000000-0000-0000-0000-00000000b007','tt-phudong','Phú Đông SkyOne','comparable','Đối thủ vừa túi tiền · yield 5–7%','[{"key":"CĐT","value":"Phú Đông Group"},{"key":"Vị trí","value":"DT743C, P. Dĩ An (gần KCN, cách ĐHQG ~9 phút)"},{"key":"Quy mô","value":"5.615 m² · 2 block · 30 tầng · ~780 căn"},{"key":"Giá","value":"~31,5–38 triệu/m² · từ ~1,7–2,7 tỷ/căn"},{"key":"Cho thuê","value":"8–15 triệu/tháng · yield 5–7%/năm"}]'::jsonb,null,'Đối thủ trực tiếp cùng phân khúc & tệp khách. So với Hoàng Nam: SkyOne giá mềm hơn (~31–38 vs ~45–60 dự kiến), gần KCN hơn; Hoàng Nam bám trục Thống Nhất/Bcons hơn. Cả hai đều bán câu chuyện "vừa túi tiền + cho thuê".',41),
  ('4632d911-c951-57f2-bf7c-192952a8aa21','00000000-0000-0000-0000-00000000b007','tt-lapura','La Pura (Phát Đạt)','comparable','Đại dự án Thuận An · áp lực cung','[]'::jsonb,null,'La Pura (Phát Đạt) — đại dự án nhiều phân khu tại Thuận An cũ, thương hiệu lớn. Khác phân khúc/quy mô so với Hoàng Nam (boutique 1 tháp), nhưng góp phần làm tăng nguồn cung căn hộ khu Bình Dương cũ giai đoạn tới.',42),
  ('c297fb12-59c2-5aac-a1fc-7a1726263e63','00000000-0000-0000-0000-00000000b007','tt-dinhvi','Định vị & SWOT','comparable','Lợi thế / điểm yếu Hoàng Nam','[]'::jsonb,null,'Lợi thế (Strengths) • CĐT Bcons track record "không bàn giao trễ", thanh khoản khu vực tốt • Vị trí cầu thuê kép (ĐHQG + KCN) + bám Metro/TOD • Quy mô nhỏ, cộng đồng gọn; giá vừa túi tiền; cú hích sáp nhập TP.HCM Điểm yếu / Thách thức (Weaknesses) • Mới động thổ → pháp lý bán hàng chưa rõ, chôn vốn tới 2028 • Mật độ xây dựng cao (~51,66%), tiện ích/cây xanh hạn chế (đất nhỏ) • Cạnh tranh dày: Bcons City/Center City, Phú Đông SkyOne; nguồn cung khu vực lớn • Mâu thuẫn số liệu gây nhiễu thông tin; là dự án hợp tác (làm rõ pháp nhân)',43),
  ('88aed627-d889-5008-9d7a-76b11b9012cc','00000000-0000-0000-0000-00000000b007','tt-thanhkhoan','Thanh khoản & nguồn cung','comparable','Cầu thuê tốt · cung khu vực lớn','[]'::jsonb,null,'Thanh khoản phân khúc này dựa vào cầu ở thực + cầu thuê hơn là đầu cơ: • Căn 1–2PN giá ~2–3,5 tỷ: tệp mua ở thực & cho thuê lớn → thanh khoản ổn. • Nguồn cung khu Dĩ An/Bình Dương cũ dồi dào (Bcons, Phú Đông, La Pura…) → cạnh tranh bán lại & cho thuê.',44),
  ('c98af431-083e-534b-aec7-a963bf4b124d','00000000-0000-0000-0000-00000000b007','dt-thesis','Luận điểm đầu tư','finance','5 trụ cột — thiên về dòng tiền cho thuê','[]'::jsonb,null,'1 · Dòng thuê thực, bền vững Cầu thuê kép từ ĐHQG (giảng viên/sinh viên) + KCN (chuyên gia/công nhân) — yield khu vực ~5–7%, cao hơn khu lõi. 2 · Giá vừa túi tiền Tổng giá ~2,2–3,5 tỷ/căn (dự kiến) — vốn vào thấp, tệp mua/thuê rộng. 3 · TOD – bám Metro Gần ga cuối Metro số 1 + Bến xe Miền Đông mới — đúng xu thế đô thị giao thông công cộng. 4 · Uy tín Bcons Track record "không bàn giao trễ", 8 dự án đã ra sổ — giảm rủi ro với dự án hình thành trong tương lai. 5 · Cú hích sáp nhập TP.HCM Địa chỉ "TP.HCM" + kỳ vọng đồng bộ hạ tầng nâng định vị khu Đông Hòa.',45),
  ('a1058ac9-f4a8-5dd3-984e-fa28041a3b66','00000000-0000-0000-0000-00000000b007','dt-dongtien','Dòng tiền (mô phỏng)','finance','Vốn thấp, trả chậm tới bàn giao 2028','[]'::jsonb,null,'Ví dụ căn 2PN ~2,8 tỷ (giả định ~50 tr/m² × ~56 m²), chính sách Bcons điển hình: Đặc điểm: vốn ban đầu thấp, gánh nặng giãn tới bàn giao. Nếu dùng vay, lãi sau ưu đãi cần dự phòng; nhưng yield khu vực 5–7% tiệm cận/đủ bù lãi vay hơn nhiều so với khu lõi (yield ~2% không đủ bù lãi) — đây là điểm cộng dòng tiền của phân khúc này.',46),
  ('ed28ac1d-4630-5f3e-a71b-af41b87bed57','00000000-0000-0000-0000-00000000b007','dt-ruiro','Bản đồ rủi ro','finance','Pháp lý sớm · số liệu · cung · bàn giao xa','[]'::jsonb,null,null,47),
  ('17970733-6c7b-58ae-9807-343c7e1b815a','00000000-0000-0000-0000-00000000b007','dt-khuyennghi','Khuyến nghị theo mục tiêu','finance','Ai nên mua — và mua thế nào','[]'::jsonb,null,null,48),
  ('f70dfc94-3098-5aaa-8aef-d26b7dff3cbc','00000000-0000-0000-0000-00000000b007','dt-trigger','Tín hiệu Mua / Thận trọng','finance','Benchmark cập nhật quyết định','[]'::jsonb,null,'Tín hiệu MUA mạnh hơn • CĐT công bố văn bản đủ điều kiện bán + GPXD rõ ràng • Bảng giá GĐ1 mềm hơn Bcons Center City (~<50 tr/m²) • Đường Thống Nhất GĐ2 & Vành đai 3 hoàn thành đúng hạn • Tiến độ thi công bám mốc bàn giao Q3/2028 Tín hiệu THẬN TRỌNG • Chậm/thiếu văn bản pháp lý bán hàng • Giá ngang/cao hơn dự án đã hiện hữu (Center City) mà không có lợi thế rõ • Nguồn cung khu vực bung mạnh làm giá thuê/giá bán đi ngang • Vướng mắc trong cơ cấu hợp tác Bcons × Hoàng Nam',49),
  ('ca208962-cb33-5ff3-bce3-4bb405640393','00000000-0000-0000-0000-00000000b007','dt-kh','Chân dung khách mua','finance','Gia đình trẻ · chuyên gia · NĐT cho thuê','[]'::jsonb,null,'Tệp khách của dự án: • Gia đình trẻ, chuyên gia, trí thức làm việc khu Đông/Thủ Đức/KCN — mua để ở, vốn vào thấp. • Nhà đầu tư cho thuê nhắm nguồn cầu giảng viên/cán bộ ĐHQG + chuyên gia KCN. • Người lao động muốn an cư gần nơi làm việc, tận dụng Metro.',50);
